      "representation": "text" | "arc" | "icon" | "text+icon" | "text+arc" | "number",
      "layout": "row" | "arc" | "standalone" | "grid",
      "group": "center" | "top" | "bottom" | "left_panel" | "right_panel" | "top_left" | "top_right" | "bottom_left" | "bottom_right",
